refsection.programlisting:
defaultcoef('co',['=' ; '+' ; '(' ; '-' ; '*'],['+' ; '-' ; '*' ; '/' ; ')'],'y=co1+co2*x1+(co3-co2)*x2')  //The coefficients are supposed prefixed by co, to be preceded by '=', '+', '(', '-' or '*' and followed by '+', '-', '*', '/', or ')';
// the equation is 'y=co1+co2*x1+(co3-co2)*x2'.
// and the result is:
 
//!co1   !
//!         !
//!co2   !
//!         !
//!co3   !
 
grocer_namecoef=defaultcoef('a',grocer_speccarb,grocer_speccara,varargin(:))// Example taken from function sur.
